+        assert_eq!(ConsciousnessLevel::from_phi(0.5), ConsciousnessLevel::Low);
+        assert_eq!(ConsciousnessLevel::from_phi(5.0), ConsciousnessLevel::Moderate);
+        assert_eq!(ConsciousnessLevel::from_phi(15.0), ConsciousnessLevel::High);
+    }
