+    pub const REVERSIBLE_IDEAL: f64 = 1.0;
+
+    /// Near-term reversible (~10× above Landauer)
+    pub const REVERSIBLE_2028: f64 = 10.0;
+
+    /// Superconducting qubits (cold, but higher per operation)
+    pub const SUPERCONDUCTING: f64 = 100.0;
+}
