+        assert!(matches!(result, ThoughtResult::Captured { .. }));
+        assert_eq!(bh.captured_count(), 1);
+    }
+
+    #[test]
+    fn test_thought_orbiting() {
+        let mut bh = CognitiveBlackHole::with_params(
