+
+    #[test]
+    fn test_escape_dynamics() {
+        let bh = CognitiveBlackHole::new();
+        let mut dynamics = EscapeDynamics::new(vec![0.3; 8], &bh);
+
+        assert!(!dynamics.can_escape());
+
+        dynamics.add_energy(10.0);
+        assert!(dynamics.escape_progress() > 0.0);
