+    }
+
+    /// Configure coarse-graining
+    pub fn set_coarse_graining(&mut self, groupings: Vec<Vec<usize>>, aggregation: AggregationType) {
+        self.coarse_grainer = CoarseGrainer {
+            groupings,
+            aggregation,
