+                activation: 0.2,
+                age: 5,
+                relationships: HashMap::new(),
+            },
+        ];
+
+        let winner = exec.arbitrate(&selves, selves[0].id, selves[1].id);
+        assert!(winner.is_some());
+    }
+}

